#include <bits/stdc++.h>
using namespace std;
int main(){
    int a,b;bool f[10]={false};f[0]=true;
    for(int i=192;i<=327;i++){
    	f[1]=f[2]=f[3]=f[4]=f[5]=f[6]=f[7]=f[8]=f[9]=false;
        if(!f[i%10])f[i%10]=true;
        else continue;
        if(!f[i/10%10])f[i/10%10]=true;
        else continue;
        if(!f[i/100])f[i/100]=true;
        else continue;
        a=2*i;
        if(!f[a%10])f[a%10]=true;
        else continue;
        if(!f[a/10%10])f[a/10%10]=true;
        else continue;
        if(!f[a/100])f[a/100]=true;
        else continue;
        b=3*i;
        if(!f[b%10])f[b%10]=true;
        else continue;
        if(!f[b/10%10])f[b/10%10]=true;
        else continue;
        if(!f[b/100])f[b/100]=true;
        else continue;
        cout<<i<<' '<<a<<' '<<b<<endl;
    }
    return 0;
}
